using System.ComponentModel;
using ModelContextProtocol.Server;

namespace HttpMcpServer.Tools;

[McpServerToolType]
public static class ServerTools
{
    [McpServerTool, Description("Greets the caller by name.")]
    public static string Greet(
        [Description("Name of the person to greet")] string name)
    {
        return $"Hello, {name}! Welcome to the MCP HTTP server.";
    }

    [McpServerTool, Description("Adds two numbers together and returns the result.")]
    public static double Add(
        [Description("First number")] double a,
        [Description("Second number")] double b)
    {
        return a + b;
    }
}

using System.ComponentModel;
using System.Text.Json;
using ModelContextProtocol.Server;

namespace HttpMcpServer.Resources;

[McpServerResourceType]
public static class ConfigResource
{
    [McpServerResource(
        UriTemplate = "config://app/settings",
        Name = "App Settings",
        MimeType = "application/json"),
     Description("Returns current application configuration data.")]
    public static string GetAppSettings()
    {
        var config = new
        {
            AppName = "HttpMcpServer",
            Version = "1.0.0",
            Environment = Environment.GetEnvironmentVariable("ASPNETCORE_ENVIRONMENT") ?? "Production",
            MaxConnections = 100,
            Features = new { CachingEnabled = true, RateLimitingEnabled = false }
        };

        return JsonSerializer.Serialize(config, new JsonSerializerOptions { WriteIndented = true });
    }

    [McpServerResource(
        UriTemplate = "config://app/endpoints",
        Name = "API Endpoints",
        MimeType = "application/json"),
     Description("Lists the available API endpoints and their descriptions.")]
    public static string GetEndpoints()
    {
        var endpoints = new[]
        {
            new { Path = "/mcp", Method = "POST", Description = "MCP Streamable HTTP endpoint" },
            new { Path = "/health", Method = "GET", Description = "Health check" }
        };

        return JsonSerializer.Serialize(endpoints, new JsonSerializerOptions { WriteIndented = true });
    }
}

